package travelcare_agent.evaluation;
import com.fasterxml.jackson.databind.ObjectMapper; import org.junit.jupiter.api.Test; import travelcare_agent.common.exception.BusinessException; import travelcare_agent.common.result.ResultCode; import travelcare_agent.dryrun.*; import travelcare_agent.evaluation.entity.*; import travelcare_agent.evaluation.repository.*; import travelcare_agent.trace.TraceQueryService; import travelcare_agent.trace.repository.TraceRunRepository; import java.util.*; import static org.assertj.core.api.Assertions.assertThatThrownBy; import static org.mockito.Mockito.*;
class EvaluationRunnerValidationTest {
 @Test void rejectsNonActiveEmptyNonMockAndUnknownStub(){EvaluationDatasetRepository datasets=mock(EvaluationDatasetRepository.class);EvaluationCaseRepository cases=mock(EvaluationCaseRepository.class);EvaluationDataset draft=dataset("DRAFT");when(datasets.findById(1L)).thenReturn(Optional.of(draft));EvaluationRunnerService service=service(datasets,cases);assertCode(()->service.start(1L,null,null),ResultCode.EVALUATION_DATASET_NOT_ACTIVE);EvaluationDataset active=dataset("ACTIVE");when(datasets.findById(1L)).thenReturn(Optional.of(active));assertCode(()->service.start(1L,"deepseek",null),ResultCode.EVALUATION_PROVIDER_NOT_ALLOWED);assertCode(()->service.start(1L,"mock","unknown"),ResultCode.EVALUATION_PROMPT_STUB_UNKNOWN);when(cases.findEnabledCasesByDatasetId(1L)).thenReturn(List.of());assertCode(()->service.start(1L,"mock","stage8-default"),ResultCode.EVALUATION_EMPTY_DATASET);}
 private EvaluationRunnerService service(EvaluationDatasetRepository d,EvaluationCaseRepository c){return new EvaluationRunnerService(d,c,mock(EvaluationRunRepository.class),mock(EvaluationCaseResultRepository.class),mock(TraceRunRepository.class),mock(DryRunReadinessChecker.class),mock(DiagnosticDryRunService.class),mock(TraceQueryService.class),mock(TraceDiffService.class),List.of(),new EvaluationPromptStubRegistry(),mock(EvaluationSideEffectGuard.class),mock(EvaluationRunReportWriter.class),new ObjectMapper());}
 private EvaluationDataset dataset(String status){EvaluationDataset d=new EvaluationDataset();d.setId(1L);d.setVersion(1);d.setDatasetKey("refund");d.setStatus(status);return d;}
 private void assertCode(org.assertj.core.api.ThrowableAssert.ThrowingCallable c,ResultCode code){assertThatThrownBy(c).isInstanceOfSatisfying(BusinessException.class,e->org.assertj.core.api.Assertions.assertThat(e.getResultCode()).isEqualTo(code));}
}
